transform_scripts.onBefore:
// Set discovery source and managed flag for all server records
source.discovery_source = 'Avennorth Pathfinder';
source.x_avnth_pathfinder_managed = 'true';

field_transforms.script:
// Normalize OS names to ServiceNow standard values
var osMap = {
    'linux': 'Linux',
    'ubuntu': 'Linux',
    'centos': 'Linux',
    'rhel': 'Linux',
    'red hat': 'Linux',
    'debian': 'Linux',
    'suse': 'Linux',
    'windows': 'Windows',
    'windows server': 'Windows',
    'aix': 'AIX',
    'solaris': 'Solaris',
    'hpux': 'HP-UX',
    'hp-ux': 'HP-UX',
    'macos': 'Mac OS',
    'darwin': 'Mac OS'
};
var osLower = (source.os || '').toLowerCase();
for (var key in osMap) {
    if (osLower.indexOf(key) >= 0) {
        answer = osMap[key];
        break;
    }
}
if (!answer) {
    answer = source.os || 'Unknown';
}

// Convert RAM from bytes to MB if needed
var ramValue = parseInt(source.ram, 10);
if (ramValue > 1048576) {
    // Likely in bytes, convert to MB
    answer = Math.round(ramValue / 1048576);
} else if (ramValue > 1024) {
    // Likely in KB, convert to MB
    answer = Math.round(ramValue / 1024);
} else {
    answer = ramValue;
}

// Normalize application names from process names when no explicit name is provided
var rawName = source.name || '';
if (!rawName && source.process_name) {
    var processMap = {
        'httpd': 'Apache HTTP Server',
        'apache2': 'Apache HTTP Server',
        'nginx': 'NGINX',
        'java': 'Java Application',
        'node': 'Node.js Application',
        'python': 'Python Application',
        'postgres': 'PostgreSQL',
        'mysqld': 'MySQL',
        'mongod': 'MongoDB',
        'redis-server': 'Redis',
        'rabbitmq-server': 'RabbitMQ',
        'kafka': 'Apache Kafka',
        'tomcat': 'Apache Tomcat',
        'iis': 'IIS Web Server',
        'w3wp': 'IIS Application Pool',
        'sqlservr': 'Microsoft SQL Server',
        'oracle': 'Oracle Database'
    };
    var procLower = source.process_name.toLowerCase();
    answer = processMap[procLower] || source.process_name;
} else {
    answer = rawName;
}

// Standardize cloud service naming: 'Provider - Service (Region)'
var provider = source.cloud_provider || 'Unknown';
var rawName = source.name || '';
var region = source.cloud_region || '';

// Only reformat if name does not already contain provider
if (rawName.indexOf(provider) < 0 && provider !== 'Unknown') {
    answer = provider + ' - ' + rawName;
} else {
    answer = rawName;
}

// Assign risk tier based on protocol type and connectivity patterns
var riskTier = source.risk_tier || '';
if (!riskTier) {
    var protocol = (source.protocol_type || '').toLowerCase();
    if (protocol === 'dicom' || protocol === 'hl7v2') {
        // Imaging and clinical data systems are typically high risk
        answer = 'high';
    } else if (protocol === 'fhir') {
        // FHIR endpoints may be read-only reference queries
        answer = 'medium';
    } else {
        answer = 'low';
    }
} else {
    answer = riskTier;
}

// Build a descriptive name for medical devices when no name is provided
var rawName = source.name || '';
if (!rawName) {
    var parts = [];
    if (source.manufacturer) parts.push(source.manufacturer);
    if (source.model_number) parts.push(source.model_number);
    if (parts.length > 0) {
        answer = parts.join(' ');
    } else {
        answer = 'Medical Device ' + (source.serial_number || source.mac_address || 'Unknown');
    }
} else {
    answer = rawName;
}

// Use OUI database lookup to determine manufacturer from MAC address
// when manufacturer is not provided in the source data
var mfg = source.manufacturer || '';
if (!mfg && source.mac_address) {
    // Extract OUI prefix (first 6 hex chars)
    var mac = (source.mac_address || '').replace(/[:\-]/g, '').toUpperCase();
    var oui = mac.substring(0, 6);
    // Common OUI prefixes for IoT manufacturers
    var ouiMap = {
        'B827EB': 'Raspberry Pi Foundation',
        'DC4F22': 'Espressif Inc.',
        'A020A6': 'Espressif Inc.',
        '00124B': 'Texas Instruments',
        '001BC5': 'Cisco Systems',
        'F0B429': 'Siemens AG',
        '000D6F': 'Ember Corporation',
        '001E8F': 'Honeywell'
    };
    answer = ouiMap[oui] || 'Unknown';
} else {
    answer = mfg;
}

// Build a descriptive name for IoT devices when no name is provided
var rawName = source.name || '';
if (!rawName) {
    var parts = [];
    if (source.iot_category) parts.push(source.iot_category);
    if (source.manufacturer) parts.push(source.manufacturer);
    if (parts.length > 0) {
        answer = 'IoT ' + parts.join(' - ');
    } else {
        answer = 'IoT Device ' + (source.mac_address || source.ip_address || 'Unknown');
    }
} else {
    answer = rawName;
}

// Map Pathfinder relationship type identifiers to ServiceNow cmdb_rel_type names
var relTypeMap = {
    'depends_on': 'Depends on::Used by',
    'sends_data_to': 'Sends data to::Receives data from',
    'runs_on': 'Runs on::Runs',
    'connects_to': 'Connects to::Connected by',
    'uses': 'Depends on::Used by',
    'hosted_on': 'Hosted on::Hosts',
    'cluster_of': 'Cluster of::Cluster is'
};
var rawType = (source.relationship_type || '').toLowerCase().replace(/\s+/g, '_');
var mappedType = relTypeMap[rawType];

if (mappedType) {
    // Look up the sys_id for this relationship type
    var relTypeGr = new GlideRecord('cmdb_rel_type');
    relTypeGr.addQuery('name', mappedType);
    relTypeGr.setLimit(1);
    relTypeGr.query();
    if (relTypeGr.next()) {
        answer = relTypeGr.getUniqueValue();
    } else {
        // Fall back to 'Depends on::Used by' if type not found
        relTypeGr = new GlideRecord('cmdb_rel_type');
        relTypeGr.addQuery('name', 'Depends on::Used by');
        relTypeGr.setLimit(1);
        relTypeGr.query();
        if (relTypeGr.next()) {
            answer = relTypeGr.getUniqueValue();
        }
    }
}
